// nfPublish stores status in global context
// Dashboard polls GET /nf/status to read it
global.set('nfPublish', function(nodeId, nodeName, fill, text) {
    var store = global.get('nfStore') || {};
    store[nodeId] = { fill: fill, text: text, name: nodeName, ts: Date.now() };
    global.set('nfStore', store);
});
global.set('nfStore', {});
node.status({ fill: 'green', shape: 'dot', text: 'ready' });
return null;

var store = global.get('nfStore') || {};
msg.payload = store;
msg.statusCode = 200;
msg.headers = {
    'Content-Type': 'application/json',
    'Access-Control-Allow-Origin': '*',
    'Cache-Control': 'no-store'
};
return msg;

